// ── LOGIN ──────────────────────────────────────────────────────────────────
function LoginScreen({ onLogin, users, setUsers }) {
  const [tab, setTab] = useState("login");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [coachEmail, setCoachEmail] = useState("");
  const [coachPassword, setCoachPassword] = useState("");
  const [isCoach, setIsCoach] = useState(false);
  const [error, setError] = useState("");
  const [notice, setNotice] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  // register fields
  const [rName, setRName] = useState("");
  const [rEmail, setREmail] = useState("");
  const [rPass, setRPass] = useState("");
  const [rPass2, setRPass2] = useState("");
  const [rGender, setRGender] = useState("");

  async function handleLogin() {
  setError("");
  setNotice("");
  setIsSubmitting(true);

  if (isCoach) {
    try {
      const authUser = await signIn(coachEmail.trim(), coachPassword);

      const coach = users.find((u) => u.role === "coach");

      if (!coach) {
        setError("Coach account exists in Supabase, but no local coach profile was found.");
        return;
      }

      if (!coach.user_id) {
        setError("Coach access is not configured correctly.");
        await supabase.auth.signOut();
        return;
      }

      if (!authUser || authUser.id !== coach.user_id) {
        setError("This account is not authorized for coach access.");
        await supabase.auth.signOut();
        return;
      }

      onLogin(coach);
    } catch (err) {
      setError(err.message || "Invalid coach email or password.");
    } finally {
      setIsSubmitting(false);
    }
  } else {
    try {
      const authUser = await signIn(email.trim(), password);

      if (!authUser) {
        setError("Login worked, but no auth user was returned.");
        return;
      }

      const found = users.find((u) => u.user_id === authUser.id);

      if (found) {
        onLogin(found);
        return;
      }

      const pendingName =
        authUser.user_metadata?.full_name ||
        authUser.user_metadata?.name ||
        authUser.email?.split("@")[0] ||
        "Athlete";
      const pendingGender = normalizeGenderValue(authUser.user_metadata?.gender);

      const { data: existingAthlete, error: existingAthleteError } = await supabase
        .from("athletes")
        .select("*")
        .eq("user_id", authUser.id)
        .maybeSingle();

      if (existingAthleteError) {
        setError(existingAthleteError.message || "Login worked, but your athlete profile could not be loaded.");
        return;
      }

      let athleteRow = existingAthlete;

      if (!athleteRow) {
        const { data: insertedAthletes, error: athleteInsertError } = await insertAthleteProfile({
          user_id: authUser.id,
          full_name: pendingName,
          role: "athlete",
          gender: pendingGender,
        });

        if (athleteInsertError) {
          setError(athleteInsertError.message || "Login worked, but your athlete profile could not be created.");
          return;
        }

        athleteRow = insertedAthletes?.[0];
      }

      const newUser = normalizeUser(athleteRow || {
        user_id: authUser.id,
        full_name: pendingName,
        role: "athlete",
      });

      setUsers((p) => [...p, newUser]);
      onLogin(newUser);
    } catch (err) {
      setError(err.message || "Invalid email or password.");
    } finally {
      setIsSubmitting(false);
    }
  }
}

  async function handleRegister() {
  const nextName = rName.trim();
  const nextEmail = rEmail.trim().toLowerCase();
  const coachEmailValue = users.find((u) => u.role === "coach")?.email?.trim().toLowerCase();

  if (!nextName || !nextEmail || !rPass || !rGender) {
    setError("All fields required");
    return;
  }

  if (rPass !== rPass2) {
    setError("Passwords don't match");
    return;
  }

  if (rPass.length < 8) {
    setError("Password must be at least 8 characters.");
    return;
  }

  if (coachEmailValue && nextEmail === coachEmailValue) {
    setError("That email is reserved for the coach account.");
    return;
  }

  try {
    setError("");
    setNotice("");
    setIsSubmitting(true);

    const signUpResult = await signUp(nextEmail, rPass, {
      fullName: nextName,
      gender: rGender,
      emailRedirectTo: window.location.origin,
    });
    const authUser = signUpResult.user;

    if (!authUser?.id) {
      throw new Error("Could not create account.");
    }

    const verificationPending =
      !signUpResult.session ||
      (authUser.identities && authUser.identities.length === 0) ||
      !authUser.email_confirmed_at;

    if (verificationPending) {
      setNotice("Check your email and verify your account before signing in.");
      setTab("login");
      setEmail(nextEmail);
      setPassword("");
      setRName("");
      setREmail("");
      setRPass("");
      setRPass2("");
      setRGender("");
      return;
    }

    setNotice("Account created. Please sign in.");
    setTab("login");
    setEmail(nextEmail);
    setPassword("");
  } catch (err) {
    setError(err.message || "Could not create account");
  } finally {
    setIsSubmitting(false);
  }
}

  return (
    <div className="login-wrap">
      <div className="login-bg" />

      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          marginBottom: 0,
          width: "100%",
          zIndex: 1,
        }}
      >
        <img
          src={GORILLA_IMG}
          alt="TTD"
          style={{
            width: 90,
            height: 90,
            objectFit: "contain",
            marginBottom: -4,
            filter: "invert(1)",
          }}
        />

        <div className="login-logo">
          TTD <span>ARENA</span>
        </div>

        <div className="login-sub">Train - Test - Dominate</div>

        <div className="login-card">
          {error && <div className="error-msg">{error}</div>}
          {notice && <div style={{ color: "var(--green)", fontSize: 12, marginBottom: 12 }}>{notice}</div>}

          {tab === "login" ? (
            <>
              <div
                style={{
                  display: "flex",
                  gap: 0,
                  marginBottom: 16,
                  border: "1px solid var(--border)",
                  borderRadius: 2,
                  overflow: "hidden",
                }}
              >
                <button
                  className={`login-tab ${!isCoach ? "active" : ""}`}
                  style={{ flex: 1 }}
                  onClick={() => {
                    setIsCoach(false);
                    setError("");
                    setNotice("");
                  }}
                >
                  Athlete
                </button>

                <button
                  className={`login-tab ${isCoach ? "active" : ""}`}
                  style={{ flex: 1 }}
                  onClick={() => {
                    setIsCoach(true);
                    setError("");
                    setNotice("");
                  }}
                >
                  Coach
                </button>
              </div>

              {isCoach ? (
                <>
                  <label className="field-label">Coach Email</label>
                  <input
                    className="field-input"
                    type="email"
                    placeholder="coach@email.com"
                    value={coachEmail}
                    onChange={(e) => {
                      setCoachEmail(e.target.value);
                      setError("");
                      setNotice("");
                    }}
                  />

                  <label className="field-label">Coach Password</label>
                  <input
                    className="field-input"
                    type="password"
                    placeholder="••••••••"
                    value={coachPassword}
                    onChange={(e) => {
                      setCoachPassword(e.target.value);
                      setError("");
                      setNotice("");
                    }}
                    onKeyDown={(e) => e.key === "Enter" && handleLogin()}
                  />
                </>
              ) : (
                <>
                  <label className="field-label">Email</label>
                  <input
                    className="field-input"
                    type="email"
                    placeholder="you@email.com"
                    value={email}
                    onChange={(e) => {
                      setEmail(e.target.value);
                      setError("");
                      setNotice("");
                    }}
                  />

                  <label className="field-label">Password</label>
                  <input
                    className="field-input"
                    type="password"
                    placeholder="••••••••"
                    value={password}
                    onChange={(e) => {
                      setPassword(e.target.value);
                      setError("");
                      setNotice("");
                    }}
                    onKeyDown={(e) => e.key === "Enter" && handleLogin()}
                  />

                  <div style={{ marginBottom: 16, fontSize: 11, color: "var(--sub)" }}>
                    Athlete accounts sign in here. Coach access is private.
                  </div>
                </>
              )}

              <button className="btn-primary" onClick={handleLogin} disabled={isSubmitting}>
                Enter →
              </button>

              <div
                style={{
                  display: "flex",
                  justifyContent: "center",
                  marginTop: 20,
                  gap: 6,
                  fontSize: 12,
                  color: "var(--sub)",
                }}
              >
                <span>Don't have an account?</span>
                <span
                  style={{ color: "var(--orange)", cursor: "pointer", fontWeight: 600 }}
                  onClick={() => {
                    setTab("register");
                    setIsCoach(false);
                    setError("");
                    setNotice("");
                  }}
                >
                  Create Account
                </span>
              </div>
            </>
          ) : (
            <>
              <div style={{ marginBottom: 16, fontSize: 11, color: "var(--sub)", textAlign: "center", letterSpacing: 1 }}>
                ATHLETE ACCOUNT SIGN UP ONLY
              </div>
              <label className="field-label">Full Name</label>
              <input
                className="field-input"
                placeholder="Your name"
                value={rName}
                onChange={(e) => { setRName(e.target.value); setError(""); setNotice(""); }}
              />

              <label className="field-label">Email</label>
              <input
                className="field-input"
                type="email"
                placeholder="you@email.com"
                value={rEmail}
                onChange={(e) => { setREmail(e.target.value); setError(""); setNotice(""); }}
              />

              <label className="field-label">Gender</label>
              <select
                className="field-select"
                value={rGender}
                onChange={(e) => { setRGender(e.target.value); setError(""); setNotice(""); }}
              >
                <option value="">Select gender</option>
                <option value="female">Female</option>
                <option value="male">Male</option>
              </select>

              <label className="field-label">Password</label>
              <input
                className="field-input"
                type="password"
                placeholder="••••••••"
                value={rPass}
                onChange={(e) => { setRPass(e.target.value); setError(""); setNotice(""); }}
              />

              <label className="field-label">Confirm Password</label>
              <input
                className="field-input"
                type="password"
                placeholder="••••••••"
                value={rPass2}
                onChange={(e) => { setRPass2(e.target.value); setError(""); setNotice(""); }}
                onKeyDown={(e) => e.key === "Enter" && handleRegister()}
              />

              <button className="btn-primary" onClick={handleRegister} disabled={isSubmitting}>
                Create Account →
              </button>

              <div
                style={{
                  display: "flex",
                  justifyContent: "center",
                  marginTop: 20,
                  gap: 6,
                  fontSize: 12,
                  color: "var(--sub)",
                }}
              >
                <span>Already have an account?</span>
                <span
                  style={{ color: "var(--orange)", cursor: "pointer", fontWeight: 600 }}
                  onClick={() => {
                    setTab("login");
                    setError("");
                    setNotice("");
                  }}
                >
                  Sign In
                </span>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

// ── WORKOUT MODAL (Coach) ──────────────────────────────────────────────────
const WORKOUT_TYPES = ["AMRAP", "For Time", "EMOM", "Interval", "PPM Conditioning", "Strength", "Weightlifting", "Gymnastics"];
const SCORE_TYPES = [
  { value: "time",      label: "Time (fastest wins)" },
  { value: "roundsreps",label: "Rounds and Reps (most wins)" },
  { value: "reps",      label: "Reps (most wins)" },
  { value: "weight",    label: "Weight (heaviest wins)" },
  { value: "calories",  label: "Calories (most wins)" },
  { value: "meters",    label: "Meters (most wins)" },
  { value: "text",      label: "Text / Notes" },
  { value: "noscore",   label: "No Score" },
];

function WorkoutModal({ workout, onSave, onClose }) {
  const [form, setForm] = useState(workout || {
    title: "", type: "For Time", scoreType: "time", rounds: 1, totalScore: false, description: "", notes: "", date: today,
  });

  function set(k, v) { setForm(f => ({ ...f, [k]: v })); }

  function handleSave() {
    if (!form.title.trim() || !form.description.trim()) return;
    const rounds = Math.max(1, parseInt(form.rounds) || 1);
    onSave({ ...form, rounds, id: workout?.id || uid(), createdBy: "coach1" });
    onClose();
  }

  const multiRound = (form.rounds || 1) > 1;
  const hasScore = form.scoreType !== "noscore";

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 520 }}>
        <div className="modal-header">
          <div className="modal-title">{workout ? "EDIT WORKOUT" : "NEW WORKOUT"}</div>
          <button className="modal-close" onClick={onClose}>X</button>
        </div>
        <div className="modal-body">
          <div className="form-row">
            <label className="field-label">Date</label>
            <input className="field-input" type="date" value={form.date} onChange={e => set("date", e.target.value)} />
          </div>
          <div className="form-grid form-row">
            <div>
              <label className="field-label">Workout Name</label>
              <input className="field-input" placeholder="FRAN, HELEN..." value={form.title} onChange={e => set("title", e.target.value.toUpperCase())} />
            </div>
            <div>
              <label className="field-label">Workout Type</label>
              <select className="field-select" value={form.type} onChange={e => set("type", e.target.value)}>
                {WORKOUT_TYPES.map(t => <option key={t}>{t}</option>)}
              </select>
            </div>
          </div>

          <div className="form-row">
            <label className="field-label">Score Type</label>
            <select className="field-select" value={form.scoreType} onChange={e => set("scoreType", e.target.value)}>
              {SCORE_TYPES.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}
            </select>
          </div>

          {hasScore && (
            <div className="form-grid form-row" style={{ alignItems: "flex-end" }}>
              <div>
                <label className="field-label">Number of Rounds</label>
                <input
                  className="field-input"
                  type="number"
                  min={1}
                  max={20}
                  value={form.rounds || 1}
                  onChange={e => set("rounds", e.target.value)}
                  placeholder="1"
                />
                <div style={{ fontSize: 11, color: "var(--sub)", marginTop: 4 }}>Athletes enter one score per round</div>
              </div>
              {multiRound && (
                <div>
                  <label className="field-label">Round Scoring</label>
                  <div style={{ display: "flex", gap: 0, border: "1px solid var(--border)", borderRadius: 2, overflow: "hidden", marginTop: 2 }}>
                    <button
                      style={{ flex: 1, padding: "9px 8px", fontSize: 12, fontFamily: "Inter", fontWeight: 600, border: "none", cursor: "pointer", background: form.totalScore ? "none" : "var(--orange)", color: form.totalScore ? "var(--sub)" : "#fff", transition: "all .15s" }}
                      onClick={() => set("totalScore", false)}
                    >Best Round</button>
                    <button
                      style={{ flex: 1, padding: "9px 8px", fontSize: 12, fontFamily: "Inter", fontWeight: 600, border: "none", cursor: "pointer", background: form.totalScore ? "var(--orange)" : "none", color: form.totalScore ? "#fff" : "var(--sub)", transition: "all .15s" }}
                      onClick={() => set("totalScore", true)}
                    >Total</button>
                  </div>
                  <div style={{ fontSize: 11, color: "var(--sub)", marginTop: 4 }}>{form.totalScore ? "Sum all rounds for leaderboard" : "Best single round counts"}</div>
                </div>
              )}
            </div>
          )}

          <div className="form-row">
            <label className="field-label">Description</label>
            <textarea className="field-textarea" rows={5} placeholder={"21-15-9\nThrusters (95/65 lb)\nPull-ups"} value={form.description} onChange={e => set("description", e.target.value)} />
          </div>
          <div className="form-row">
            <label className="field-label">Coach Notes (optional)</label>
            <input className="field-input" placeholder="Scaling options, tips..." value={form.notes} onChange={e => set("notes", e.target.value)} />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-sm" onClick={onClose}>Cancel</button>
          <button className="btn-primary" style={{ width: "auto", padding: "10px 28px", fontSize: 16 }} onClick={handleSave}>SAVE WORKOUT</button>
        </div>
      </div>
    </div>
  );
}

// ── SCORE MODAL ────────────────────────────────────────────────────────────
function computeDisplayValue(roundValues, scoreType, totalScore) {
  const vals = roundValues.filter(v => v.trim() !== "");
  if (vals.length === 0) return "";
  if (scoreType === "time") {
    if (totalScore) {
      const toSec = v => { const p = v.split(":").map(Number); return p.length === 2 ? p[0]*60+p[1] : Number(v); };
      const total = vals.reduce((s,v) => s + toSec(v), 0);
      return Math.floor(total/60) + ":" + String(total%60).padStart(2,"0");
    }
    const toSec = v => { const p = v.split(":").map(Number); return p.length === 2 ? p[0]*60+p[1] : Number(v); };
    return vals.reduce((best, v) => toSec(v) < toSec(best) ? v : best);
  }
  if (scoreType === "roundsreps") {
    const toNum = v => { const p = v.toString().split("+").map(Number); return (p[0]||0)*1000+(p[1]||0); };
    if (totalScore) {
      const rounds = vals.reduce((s,v) => s + (parseInt(v.split("+")[0])||0), 0);
      const reps = vals.reduce((s,v) => s + (parseInt(v.split("+")[1])||0), 0);
      return reps > 0 ? rounds + "+" + reps : String(rounds);
    }
    return vals.reduce((best,v) => toNum(v) > toNum(best) ? v : best);
  }
  const nums = vals.map(v => parseFloat(v.replace("+","."))||0);
  if (totalScore) return String(nums.reduce((s,n) => s+n, 0));
  return String(Math.max(...nums));
}

function ScoreModal({ workout, existingScore, athleteId, onSave, onClose }) {
  const rounds = Math.max(1, parseInt(workout.rounds) || 1);
  const isNoScore = workout.scoreType === "noscore";

  // Initialize round values from existing score
  const initRoundVals = () => {
    if (existingScore?.roundValues) return existingScore.roundValues;
    if (existingScore?.value && rounds === 1) return [existingScore.value];
    return Array(rounds).fill("");
  };

  const [roundValues, setRoundValues] = useState(initRoundVals);
  const [rx, setRx] = useState(existingScore?.rx ?? true);
  const [notes, setNotes] = useState(existingScore?.notes || "");

  function setRound(i, v) { setRoundValues(rv => { const n = [...rv]; n[i] = v; return n; }); }

  function handleSave() {
    if (!isNoScore && roundValues.every(v => !v.trim())) return;
    const displayVal = isNoScore ? "-" : computeDisplayValue(roundValues, workout.scoreType, workout.totalScore);
    onSave({
      id: existingScore?.id || uid(),
      workoutId: workout.id,
      userId: athleteId,
      value: displayVal,
      roundValues,
      rx,
      notes,
    });
    onClose();
  }

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <div>
            <div className="modal-title">LOG SCORE</div>
            <div style={{ fontSize: 12, color: "var(--sub)", marginTop: 2 }}>{workout.title} - <span style={{ color: "var(--orange)" }}>{workout.type}</span></div>
          </div>
          <button className="modal-close" onClick={onClose}>X</button>
        </div>
        <div className="modal-body">
          {!isNoScore && (
            <>
              {rounds === 1 ? (
                <div className="form-row">
                  <label className="field-label">{scoreLabel(workout.scoreType)}</label>
                  <input className="field-input" placeholder={scorePlaceholder(workout.scoreType)} value={roundValues[0] || ""} onChange={e => setRound(0, e.target.value)} autoFocus />
                </div>
              ) : (
                <div className="form-row">
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                    <label className="field-label" style={{ marginBottom: 0 }}>{rounds} Rounds - {scoreLabel(workout.scoreType)}</label>
                    <span style={{ fontSize: 11, color: "var(--sub)", letterSpacing: 1 }}>{workout.totalScore ? "TOTAL" : "BEST ROUND"} counts</span>
                  </div>
                  {Array.from({ length: rounds }, (_, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
                      <span style={{ fontSize: 12, color: "var(--sub)", fontFamily: "Barlow Condensed", width: 60, flexShrink: 0, letterSpacing: 1 }}>ROUND {i+1}</span>
                      <input
                        className="field-input"
                        style={{ marginBottom: 0 }}
                        placeholder={scorePlaceholder(workout.scoreType)}
                        value={roundValues[i] || ""}
                        onChange={e => setRound(i, e.target.value)}
                        autoFocus={i === 0}
                      />
                    </div>
                  ))}
                  {roundValues.some(v => v.trim()) && (
                    <div style={{ marginTop: 8, padding: "8px 12px", background: "var(--dark)", borderRadius: 2, fontSize: 13, color: "var(--sub)" }}>
                      <span>Leaderboard score: </span>
                      <span style={{ color: "var(--green)", fontFamily: "JetBrains Mono", fontWeight: 600 }}>
                        {computeDisplayValue(roundValues.map(v => v||"0"), workout.scoreType, workout.totalScore) || "-"}
                      </span>
                    </div>
                  )}
                </div>
              )}
            </>
          )}
          <div className="form-row">
            <label className="field-label">Rx / Scaled</label>
            <div className="rx-toggle">
              <button className={`rx-opt ${rx ? "active rx" : ""}`} onClick={() => setRx(true)}>RX</button>
              <button className={`rx-opt ${!rx ? "active sc" : ""}`} onClick={() => setRx(false)}>SCALED</button>
            </div>
          </div>
          <div className="form-row">
            <label className="field-label">Notes (optional)</label>
            <input className="field-input" placeholder="How'd it feel?" value={notes} onChange={e => setNotes(e.target.value)} />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn-sm" onClick={onClose}>Cancel</button>
          <button className="btn-score" style={{ fontFamily: "Barlow Condensed", fontSize: 16, padding: "10px 28px" }} onClick={handleSave}>SUBMIT SCORE</button>
        </div>
      </div>
    </div>
  );
}

// ── WORKOUT CARD ───────────────────────────────────────────────────────────
function ScoreDetailModal({
  workout,
  score,
  athlete,
  comments,
  allUsers,
  currentUser,
  onClose,
  onPostComment,
  onViewProfile,
}) {
  const [input, setInput] = useState("");

  useEffect(() => {
    setInput("");
  }, [score?.id]);

  function ini(name) {
    return (name || "?")
      .split(" ")
      .map((n) => n[0])
      .join("");
  }

  function getUser(id) {
    return allUsers.find((u) => u.user_id === id || u.id === id);
  }

  async function submitComment() {
    const text = input.trim();
    if (!text || !score) return;

    const saved = await onPostComment?.({
      scoreId: score.id,
      ownerId: score.user_id || score.userId,
      authorId: currentUser.id,
      text,
    });

    if (saved !== false) {
      setInput("");
    }
  }

  const scoreComments = comments.filter((c) => c.scoreId === score?.id);
  const roundValues = (score?.roundValues || []).filter((value) => String(value || "").trim());

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 560 }}>
        <div className="modal-header">
          <div>
            <div className="modal-title">SCORE DETAILS</div>
            <div style={{ fontSize: 11, color: "var(--sub)", letterSpacing: 1, marginTop: 4 }}>
              {workout?.title || "Workout"}
            </div>
          </div>
          <button className="modal-close" onClick={onClose}>X</button>
        </div>

        <div className="modal-body">
          <div className="score-detail-head">
            <div className="score-detail-avatar">
              {avatarSrc(athlete) ? (
                <img src={avatarSrc(athlete)} alt={formatDisplayName(athlete)} />
              ) : (
                ini(formatDisplayName(athlete))
              )}
            </div>
            <div style={{ minWidth: 0, flex: 1 }}>
              <div className="score-detail-name">{formatDisplayName(athlete)}</div>
              <div className="score-detail-sub">{score?.date ? relTime(score.date) : "Logged score"}</div>
            </div>
          </div>

          <div className="score-detail-card">
            <div className="score-detail-card-top">
              <div className="score-detail-value">
                {workout?.scoreType !== "noscore" ? `${score?.score || "-"}${score?.rx ? "" : " s"}` : "Completed"}
              </div>
              <div className={`score-detail-rx ${score?.rx ? "rx" : "scaled"}`}>
                {score?.rx ? "RX" : "Scaled"}
              </div>
            </div>

            <div className="score-detail-meta">
              {score?.notes ? (
                <div>
                  <div className="score-detail-label">Athlete Notes</div>
                  <div className="score-detail-text">{score.notes}</div>
                </div>
              ) : null}

              {roundValues.length > 0 ? (
                <div>
                  <div className="score-detail-label">Round Breakdown</div>
                  <div className="score-detail-rounds">
                    {roundValues.map((value, index) => (
                      <div key={`${score.id}-round-${index}`} className="score-round-pill">
                        Round {index + 1}: {value}
                      </div>
                    ))}
                  </div>
                </div>
              ) : null}
            </div>

            {athlete && onViewProfile ? (
              <div className="score-detail-actions">
                <button
                  className="score-detail-profile"
                  onClick={() => {
                    onClose();
                    onViewProfile(athlete);
                  }}
                >
                  View Athlete Profile
                </button>
              </div>
            ) : null}
          </div>

          <div className="comments-section" style={{ marginTop: 0, paddingTop: 0, borderTop: "none" }}>
            <div className="section-title" style={{ fontSize: 18, marginBottom: 12 }}>COMMENTS</div>
            <div className="comments-list">
              {scoreComments.length === 0 ? (
                <div className="empty-sm">No comments yet. Add the first one.</div>
              ) : (
                scoreComments.map((comment) => {
                  const author = getUser(comment.authorId);
                  return (
                    <div key={comment.id} className="comment-item">
                      <div className="comment-av">
                        {avatarSrc(author) ? (
                          <img src={avatarSrc(author)} alt={formatDisplayName(author)} />
                        ) : (
                          ini(formatDisplayName(author))
                        )}
                      </div>
                      <div>
                        <div className="comment-author">{formatDisplayName(author)}</div>
                        <div className="comment-text">{comment.text}</div>
                        <div className="comment-time">{relTime(comment.date)}</div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>

            <div className="comment-input-row">
              <input
                className="comment-input"
                placeholder="Add a comment..."
                value={input}
                autoFocus
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && !e.shiftKey) {
                    e.preventDefault();
                    submitComment();
                  }
                }}
              />
              <button className="comment-post" onClick={submitComment}>Post</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function WorkoutCard({
  workout,
  scores,
  currentUser,
  allUsers,
  onLogScore,
  onEdit,
  onDelete,
  comments,
  onPostComment,
  onViewProfile
}) {
  const [showLB, setShowLB] = useState(false);
  const [selectedScore, setSelectedScore] = useState(null);

  const myScore = scores.find(
    (s) => s.user_id === currentUser.id && s.workout_id === workout.id
  );

  const ranked = getRank(scores, workout.scoreType);

  function getUser(id) {
  return allUsers.find((u) => u.user_id === id || u.id === id);
}

function displayName(u) {
  return formatDisplayName(u);
}

  function ini(name) {
    return (name || "?")
      .split(" ")
      .map((n) => n[0])
      .join("");
  }

  function genderGroup(user) {
    const gender = normalizeGenderValue(user?.gender);
    if (gender === "female") return "women";
    if (gender === "male") return "men";
    return "open";
  }

  const leaderboardGroups = [
    {
      key: "men",
      title: "Men",
      scores: ranked.filter((score) => genderGroup(getUser(score.user_id || score.userId)) === "men"),
    },
    {
      key: "women",
      title: "Women",
      scores: ranked.filter((score) => genderGroup(getUser(score.user_id || score.userId)) === "women"),
    },
    {
      key: "open",
      title: "Unassigned",
      subtitle: "Athletes missing gender",
      scores: ranked.filter((score) => genderGroup(getUser(score.user_id || score.userId)) === "open"),
    },
  ].filter((group) => group.scores.length > 0);

  return (
    <div className="workout-card">
      <div className="wod-header">
        <div className="wod-title-wrap">
          <div className="wod-title">{workout.title}</div>
          <span className="wod-type-badge">{workout.type}</span>
        </div>
      </div>

      <div className="wod-body">
        <div className="wod-desc">{workout.description}</div>
      </div>

      <div className="wod-footer">
        <button
          className="btn-sm"
          style={{ flex: "0 0 auto" }}
          onClick={() => setShowLB((v) => !v)}
        >
          {showLB ? "Hide" : `${scores.length} Scores`}
        </button>

        {currentUser.role === "athlete" && (
          myScore ? (
            <button
              className="btn-my-score"
              style={{ flex: 1 }}
              onClick={() => onLogScore(workout, myScore)}
            >
              {workout.scoreType !== "noscore" ? `${myScore.score}${myScore.rx ? "" : " s"}` : "Done"}
            </button>
          ) : (
            <button
              className="btn-score"
              style={{ flex: 1 }}
              onClick={() => onLogScore(workout, null)}
            >
              LOG SCORE
            </button>
          )
        )}

        {currentUser.role === "coach" && (
          <div style={{ display: "flex", gap: 8 }}>
            <button className="btn-sm" onClick={() => onEdit(workout)}>
              Edit
            </button>
            <button className="btn-danger" onClick={() => onDelete(workout.id)}>
              Delete
            </button>
          </div>
        )}
      </div>

      {showLB && (
  <div className="leaderboard">
    {ranked.length === 0 ? (
      <div className="empty-sm">No scores yet.</div>
    ) : (
      leaderboardGroups.map((group) => (
        <div key={group.key} className="leaderboard-group">
          <div className="leaderboard-group-title">{group.title}</div>
          {group.subtitle ? <div className="leaderboard-group-sub">{group.subtitle}</div> : null}
          {group.scores.map((s, i) => {
            const u = getUser(s.user_id || s.userId);
            const scoreComments = comments.filter((c) => c.scoreId === s.id);

            return (
              <div
                key={s.id}
                className="lb-row clickable"
                onClick={() => setSelectedScore(s)}
              >
                <div
                  className="lb-left"
                  style={{ cursor: "pointer" }}
                >
                  <div className="lb-rank">#{i + 1}</div>
                  <div className="avatar">
                    {u?.avatar_url ? (
                      <img src={u.avatar_url} alt={displayName(u)} className="avatar-img" />
                    ) : (
                      ini(displayName(u))
                    )}
                  </div>
                  <div className="lb-user-meta">
                    <div className="lb-name">{displayName(u)}</div>
                    <div className="lb-sub">{s.rx ? "RX" : "Scaled"}</div>
                  </div>
                </div>

                <div className="lb-right">
                  <div className="lb-score-pill">
                    {workout.scoreType !== "noscore" ? `${s.score}${s.rx ? "" : " s"}` : "Completed"}
                  </div>

                  <button
                    className="btn-link lb-comment-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedScore(s);
                    }}
                  >
                    {scoreComments.length > 0 ? `Comments (${scoreComments.length})` : "Add comment"}
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      ))
    )}
  </div>
)}

      {selectedScore && (
        <ScoreDetailModal
          workout={workout}
          score={selectedScore}
          athlete={getUser(selectedScore.user_id || selectedScore.userId)}
          comments={comments}
          allUsers={allUsers}
          currentUser={currentUser}
          onClose={() => setSelectedScore(null)}
          onPostComment={onPostComment}
          onViewProfile={onViewProfile}
        />
      )}
    </div>
  );
}

// ── CHAT VIEW ─────────────────────────────────────────────────────────────
function ChatView({ currentUser, allUsers, messages, onSendMessage, onMarkConversationRead }) {
  const isCoach = currentUser.role === "coach";
  const messagesEndRef = useRef(null);

  // For athlete: only convo with coach. For coach: list of all athletes with convos
  const coachUser = allUsers.find(u => u.role === "coach");
  const athletes = allUsers.filter(u => u.role === "athlete");

  // Selected conversation partner
  const [selectedId, setSelectedId] = useState(() => {
    if (!isCoach) return coachUser?.id || null;
    // Coach: start with no selection (WhatsApp-style list view)
    return null;
  });

  const [input, setInput] = useState("");

  // Get conversation between currentUser and selectedId
  function getConvo(otherId) {
    return messages
      .filter(m =>
        (m.fromId === currentUser.id && m.toId === otherId) ||
        (m.fromId === otherId && m.toId === currentUser.id)
      )
      .sort((a, b) => new Date(a.date) - new Date(b.date));
  }

  function getUnreadCount(otherId) {
    return messages.filter(m => m.fromId === otherId && m.toId === currentUser.id && !m.read).length;
  }

  function getLastMessage(otherId) {
    const convo = getConvo(otherId);
    return convo[convo.length - 1] || null;
  }

  async function selectPerson(id) {
    setSelectedId(id);
    await onMarkConversationRead?.(currentUser.id, id);
  }

  async function sendMessage() {
    const text = input.trim();
    if (!text || !selectedId) return;
    const saved = await onSendMessage?.({
      fromId: currentUser.id,
      toId: selectedId,
      text,
    });
    if (saved !== false) {
      setInput("");
    }
  }

  // Scroll to bottom when convo changes
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [selectedId, messages.length]);

  // Mark as read on select
  useEffect(() => {
    if (selectedId) {
      onMarkConversationRead?.(currentUser.id, selectedId);
    }
  }, [currentUser.id, onMarkConversationRead, selectedId]);

  function ini(name) { return (name || "?").split(" ").map(n => n[0]).join(""); }

  function formatMsgTime(dateStr) {
    const d = new Date(dateStr);
    const now = new Date();
    const diffMs = now - d;
    const diffDays = Math.floor(diffMs / 86400000);
    if (diffDays === 0) return d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
    if (diffDays === 1) return "Yesterday " + d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" }) + " " + d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
  }

  function shouldShowDateDivider(msgs, idx) {
    if (idx === 0) return true;
    const prev = new Date(msgs[idx-1].date);
    const curr = new Date(msgs[idx].date);
    return prev.toDateString() !== curr.toDateString();
  }

  function formatDividerDate(dateStr) {
    const d = new Date(dateStr);
    const now = new Date();
    if (d.toDateString() === now.toDateString()) return "Today";
    const yesterday = new Date(now - 86400000);
    if (d.toDateString() === yesterday.toDateString()) return "Yesterday";
    return d.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" });
  }

  const selectedUser = allUsers.find(u => u.id === selectedId);
  const convo = selectedId ? getConvo(selectedId) : [];

  // For athlete view (no sidebar, just chat with coach)
  if (!isCoach) {
    return (
      <div className="chat-layout" style={{ height: "calc(100vh - 112px)" }}>
        <div className="chat-main">
          <div className="chat-header">
            <div style={{ width: 38, height: 38, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontFamily: "Barlow Condensed", color: "var(--orange)", overflow: "hidden" }}>
              {avatarSrc(coachUser) ? <img src={avatarSrc(coachUser)} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(formatDisplayName(coachUser) || "Coach")}
            </div>
            <div>
              <div className="chat-header-name">{formatDisplayName(coachUser) || "Coach"}</div>
              <div className="chat-header-role">Head Coach</div>
            </div>
          </div>
          <div className="chat-messages">
            {convo.length === 0 && (
              <div className="chat-empty">
                <div style={{ fontSize: 40 }}>💬</div>
                <div style={{ fontSize: 14, fontWeight: 600 }}>No messages yet</div>
                <div style={{ fontSize: 12 }}>Ask the coach anything about your training!</div>
              </div>
            )}
            {convo.map((msg, i) => {
              const isMine = msg.fromId === currentUser.id;
              const sender = allUsers.find(u => u.id === msg.fromId);
              return (
                <div key={msg.id}>
                  {shouldShowDateDivider(convo, i) && (
                    <div className="chat-date-divider">{formatDividerDate(msg.date)}</div>
                  )}
                  <div className={`chat-bubble-wrap ${isMine ? "mine" : ""}`}>
                    <div className="chat-bubble-av">
                      {avatarSrc(sender) ? <img src={avatarSrc(sender)} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(formatDisplayName(sender))}
                    </div>
                    <div style={{ flex: 1, minWidth: 0, maxWidth: "calc(100% - 34px)" }}>
                      <div style={{
                        display: "block",
                        maxWidth: "68%",
                        padding: "9px 13px",
                        borderRadius: 14,
                        fontSize: 13,
                        lineHeight: 1.5,
                        wordBreak: "break-word",
                        overflowWrap: "break-word",
                        whiteSpace: "pre-wrap",
                        writingMode: "horizontal-tb",
                        textOrientation: "mixed",
                        direction: "ltr",
                        background: isMine ? "var(--orange)" : "var(--card)",
                        color: isMine ? "#fff" : "var(--text)",
                        border: isMine ? "none" : "1px solid var(--border)",
                        borderBottomRightRadius: isMine ? 3 : 14,
                        borderBottomLeftRadius: isMine ? 14 : 3,
                      }}>{msg.text}</div>
                      <div className="chat-bubble-time">{formatMsgTime(msg.date)}</div>
                    </div>
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>
          <div className="chat-input-area">
            <textarea
              className="chat-input"
              rows={1}
              placeholder="Message coach..."
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
            />
            <button className="chat-send" disabled={!input.trim()} onClick={sendMessage}>Send</button>
          </div>
        </div>
      </div>
    );
  }

  // Coach view: WhatsApp-style full-screen list, tap to open conversation
  if (isCoach && selectedId) {
    return (
      <div className="chat-layout" style={{ height: "calc(100vh - 112px)" }}>
        <div className="chat-main">
          <div className="chat-header" style={{ cursor: "pointer" }} onClick={() => setSelectedId(null)}>
            <div style={{ width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, color: "var(--orange)", marginRight: 4 }}>‹</div>
            <div style={{ width: 38, height: 38, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, fontFamily: "Barlow Condensed", color: "var(--orange)", overflow: "hidden" }}>
              {avatarSrc(selectedUser) ? <img src={avatarSrc(selectedUser)} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(formatDisplayName(selectedUser))}
            </div>
            <div>
              <div className="chat-header-name">{formatDisplayName(selectedUser)}</div>
              <div className="chat-header-role">Athlete</div>
            </div>
          </div>
          <div className="chat-messages">
            {convo.length === 0 && (
              <div className="chat-empty">
                <div style={{ fontSize: 40 }}>Chat</div>
                <div style={{ fontSize: 14, fontWeight: 600 }}>No messages yet</div>
                <div style={{ fontSize: 12 }}>Start a conversation with {formatDisplayName(selectedUser)}</div>
              </div>
            )}
            {convo.map((msg, i) => {
              const isMine = msg.fromId === currentUser.id;
              const sender = allUsers.find(u => u.id === msg.fromId);
              return (
                <div key={msg.id}>
                  {shouldShowDateDivider(convo, i) && (
                    <div className="chat-date-divider">{formatDividerDate(msg.date)}</div>
                  )}
                  <div className={`chat-bubble-wrap ${isMine ? "mine" : ""}`}>
                    <div className="chat-bubble-av">
                      {avatarSrc(sender) ? <img src={avatarSrc(sender)} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(formatDisplayName(sender))}
                    </div>
                    <div style={{ flex: 1, minWidth: 0, maxWidth: "calc(100% - 34px)" }}>
                      <div style={{
                        display: "block",
                        maxWidth: "68%",
                        padding: "9px 13px",
                        borderRadius: 14,
                        fontSize: 13,
                        lineHeight: 1.5,
                        wordBreak: "break-word",
                        overflowWrap: "break-word",
                        whiteSpace: "pre-wrap",
                        writingMode: "horizontal-tb",
                        textOrientation: "mixed",
                        direction: "ltr",
                        background: isMine ? "var(--orange)" : "var(--card)",
                        color: isMine ? "#fff" : "var(--text)",
                        border: isMine ? "none" : "1px solid var(--border)",
                        borderBottomRightRadius: isMine ? 3 : 14,
                        borderBottomLeftRadius: isMine ? 14 : 3,
                      }}>{msg.text}</div>
                      <div className="chat-bubble-time">{formatMsgTime(msg.date)}</div>
                    </div>
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>
          <div className="chat-input-area">
            <textarea
              className="chat-input"
              rows={1}
              placeholder={`Reply to ${formatDisplayName(selectedUser)}...`}
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
            />
            <button className="chat-send" disabled={!input.trim()} onClick={sendMessage}>Send</button>
          </div>
        </div>
      </div>
    );
  }

  // Coach: conversation list (WhatsApp-style)
  if (isCoach) {
    return (
      <div style={{ background: "var(--dark)", minHeight: "calc(100vh - 112px)" }}>
        <div style={{ padding: "16px 16px 8px", fontSize: 12, fontFamily: "Barlow Condensed", letterSpacing: 2, color: "var(--sub)" }}>MESSAGES</div>
        {athletes.map(a => {
          const last = getLastMessage(a.id);
          const unread = getUnreadCount(a.id);
          const lastTime = last ? formatMsgTime(last.date) : null;
          return (
            <div key={a.id} onClick={() => selectPerson(a.id)} style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 16px", borderBottom: "1px solid var(--border)", cursor: "pointer", position: "relative" }}>
              <div style={{ width: 46, height: 46, borderRadius: "50%", background: "var(--orange-dim)", border: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, fontFamily: "Barlow Condensed", color: "var(--orange)", flexShrink: 0, overflow: "hidden" }}>
                {avatarSrc(a) ? <img src={avatarSrc(a)} style={{ width: "100%", height: "100%", objectFit: "cover" }} alt="" /> : ini(formatDisplayName(a))}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{formatDisplayName(a)}</div>
                  {lastTime && <div style={{ fontSize: 11, color: "var(--sub)", flexShrink: 0 }}>{lastTime}</div>}
                </div>
                {last && <div style={{ fontSize: 12, color: "var(--sub)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", marginTop: 2 }}>{last.fromId === currentUser.id ? "You: " : ""}{last.text}</div>}
              </div>
              {unread > 0 && <div style={{ width: 8, height: 8, borderRadius: "50%", background: "var(--orange)", flexShrink: 0 }} />}
            </div>
          );
        })}
      </div>
    );
  }
}

// ── COACH VIEW ─────────────────────────────────────────────────────────────
function CoachView({ user, workouts, scores, setWorkouts, setScores, allUsers, comments, notifications, onViewProfile, messages, onPostComment, onSendMessage, onMarkConversationRead, onLogout }) {
  const [tab, setTab] = useState("workouts");
  const [selectedDate, setSelectedDate] = useState(today);
  const [showModal, setShowModal] = useState(false);
  const [editingWod, setEditingWod] = useState(null);

  const [dateOffset, setDateOffset] = useState(0);
  const WINDOW = 7;
  const dates = Array.from({ length: WINDOW }, (_, i) => {
    return formatDateKey(addDays(new Date(), dateOffset + i));
  });
  const canGoFuture = dateOffset < 30;
  const canGoPast = dateOffset > -6;

  const filtered = workouts.filter(w => w.date === selectedDate);
  const athletes = allUsers.filter(u => u.role === "athlete");
  const totalScores = scores.length;
  const unreadMsgs = messages.filter(m => m.toId === user.id && !m.read).length;

async function handleSaveWorkout(wod) {
  const isRealUuid =
    typeof wod.id === "string" &&
    /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(wod.id);

  if (isRealUuid) {
    const updateRow = buildWorkoutRow(wod);
    const { error, persistedRow } = await persistWorkoutMutation(
      (row) =>
        supabase
          .from("workouts")
          .update(row)
          .eq("id", wod.id),
      updateRow
    );

    if (error) {
      console.error("ERROR UPDATING WORKOUT:", error);
      alert(`Workout did not save: ${error.message}`);
      return;
    }

    const normalizedWorkout = normalizeWorkout({
      ...wod,
      ...persistedRow,
      id: wod.id,
    });

    setWorkouts((ws) =>
      ws.map((w) => (w.id === wod.id ? { ...w, ...normalizedWorkout } : w))
    );

    return;
  }

const insertRow = {
  ...buildWorkoutRow(wod),
  created_by: (await supabase.auth.getUser()).data.user.id,
};

  const { data, error, persistedRow } = await persistWorkoutMutation(
    (row) =>
      supabase
        .from("workouts")
        .insert([row])
        .select()
        .single(),
    insertRow
  );

  if (error) {
    console.error("ERROR INSERTING WORKOUT:", error);
    alert(`Workout did not save: ${error.message}`);
    return;
  }

  const normalizedWorkout = normalizeWorkout({
    ...persistedRow,
    ...data,
  });

  setWorkouts((ws) => [normalizedWorkout, ...ws]);
}

async function handleDeleteWorkout(id) {
  if (!window.confirm("Delete this workout?")) return;

  const isRealUuid =
    typeof id === "string" &&
    /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(id);

  if (!isRealUuid) {
    setWorkouts((ws) => ws.filter((w) => w.id !== id));
    setScores((ss) => ss.filter((s) => s.workout_id !== id));
    return;
  }

  const { error: scoreDeleteError } = await supabase
    .from("scores")
    .delete()
    .eq("workout_id", id);

  if (scoreDeleteError) {
    console.error("ERROR DELETING RELATED SCORES:", scoreDeleteError);
    alert(`Could not delete related scores: ${scoreDeleteError.message}`);
    return;
  }

const { data: deletedWorkoutRows, error: workoutDeleteError } = await supabase
  .from("workouts")
  .delete()
  .eq("id", id)
  .select();

if (workoutDeleteError) {
  console.error("ERROR DELETING WORKOUT:", workoutDeleteError);
  alert(`Workout did not delete: ${workoutDeleteError.message}`);
  return;
}

if (!deletedWorkoutRows || deletedWorkoutRows.length === 0) {
  alert("Supabase did not delete any workout rows.");
  return;
}

  setWorkouts((ws) => ws.filter((w) => w.id !== id));
  setScores((ss) => ss.filter((s) => s.workout_id !== id));
}
  const navItems = [
    { id: "workouts", label: "Workouts" },
    { id: "chat", label: "Chat" },
    { id: "athletes", label: "Athletes" },
    { id: "overview", label: "Overview" },
  ];

  function CoachNavIcon({ id }) {
    const s = { width: 20, height: 20, strokeWidth: 1.75, fill: "none", stroke: "currentColor", strokeLinecap: "round", strokeLinejoin: "round" };
    if (id === "workouts") return (
      <svg viewBox="0 0 24 24" style={s}><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M8 2v2M16 2v2M3 8h18"/><path d="M8 12h.01M12 12h.01M16 12h.01M8 16h.01M12 16h.01"/></svg>
    );
    if (id === "chat") return (
      <svg viewBox="0 0 24 24" style={s}><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
    );
    if (id === "athletes") return (
      <svg viewBox="0 0 24 24" style={s}><circle cx="9" cy="7" r="4"/><path d="M3 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/><path d="M21 21v-2a4 4 0 0 0-3-3.87"/></svg>
    );
    if (id === "overview") return (
      <svg viewBox="0 0 24 24" style={s}><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/></svg>
    );
    return null;
  }

  return (
    <>
      <div className="athlete-page-wrap">
        {tab === "chat" ? (
          <ChatView
            currentUser={user}
            allUsers={allUsers}
            messages={messages}
            onSendMessage={onSendMessage}
            onMarkConversationRead={onMarkConversationRead}
          />
        ) : (
        <div className="main">
          {tab === "workouts" && (
            <>
              <div className="date-nav">
                <button className="date-arrow" onClick={() => setDateOffset(o => o - 1)} disabled={!canGoPast}>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
                </button>
                <div className="date-strip-wrap">
                  <div className="date-strip">
                    {dates.map(d => (
                      <button key={d} className={`date-pill ${d === selectedDate ? "active" : ""}`} onClick={() => setSelectedDate(d)}>
                        {d === today ? "Today" : formatDate(d)}
                      </button>
                    ))}
                  </div>
                </div>
                <button className="date-arrow" onClick={() => setDateOffset(o => o + 1)} disabled={!canGoFuture}>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
                </button>
              </div>

              <div className="section-header">
                <div className="section-title">{selectedDate === today ? "TODAY'S WORKOUTS" : formatDate(selectedDate).toUpperCase()}</div>
                <button className="btn-primary" style={{ width: "auto", padding: "8px 14px", fontSize: 13, whiteSpace: "nowrap", flexShrink: 0 }} onClick={() => { setEditingWod(null); setShowModal(true); }}>
                  + NEW WORKOUT
                </button>
              </div>

              {filtered.length === 0 ? (
                <GorillaEmptyState text="No workouts programmed for today" />
              ) : (
                <div className="workout-grid">
                  {filtered.map(w => (
                    <WorkoutCard
                      key={w.id}
                      workout={w}
                      scores={scores.filter(s => s.workout_id === w.id)}
                      currentUser={user}
                      allUsers={allUsers}
                      onLogScore={() => {}}
                      onEdit={wod => { setEditingWod(wod); setShowModal(true); }}
                      onDelete={handleDeleteWorkout}
                      comments={comments}
                      onPostComment={onPostComment}
                      onViewProfile={onViewProfile}
                    />
                  ))}
                </div>
              )}
            </>
          )}

          {tab === "athletes" && (
            <>
              <div className="section-header">
                <div className="section-title">ALL ATHLETES</div>
              </div>
              <div className="athlete-grid" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))" }}>
                {athletes.map(a => {
                  const aScores = scores.filter(s => s.userId === a.id);
                  const lastScore = aScores.length > 0 ? aScores.sort((x,y) => new Date(y.date) - new Date(x.date))[0] : null;
                  const lastActiveStr = lastScore
                    ? (() => {
                        const d = new Date(lastScore.date);
                        if (Number.isNaN(d.getTime())) return "No activity yet";
                        const now = new Date();
                        const diffDays = Math.floor((now - d) / 86400000);
                        if (diffDays === 0) return "Active today";
                        if (diffDays === 1) return "Active yesterday";
                        if (diffDays < 7) return `Active ${diffDays}d ago`;
                        if (diffDays < 30) return `Active ${Math.floor(diffDays/7)}w ago`;
                        return `Active ${Math.floor(diffDays/30)}mo ago`;
                      })()
                    : "No activity yet";
                  return (
                    <div key={a.id} className="athlete-card" style={{ cursor: "default", textAlign: "left" }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                        <div className="athlete-avatar" style={{ background: "var(--orange-dim)", color: "var(--orange)", overflow: "hidden" }}>
                          {avatarSrc(a)
                            ? <img src={avatarSrc(a)} alt={formatDisplayName(a)} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                            : formatDisplayName(a).split(" ").map(n => n[0]).join("")}
                        </div>
                        <div>
                          <div style={{ fontWeight: 600, fontSize: 14 }}>{formatDisplayName(a)}</div>
                          <div style={{ fontSize: 11, color: "var(--sub)" }}>{lastActiveStr}</div>
                        </div>
                      </div>
                      <div style={{ fontSize: 12, color: "var(--sub)" }}>{aScores.length} score{aScores.length !== 1 ? "s" : ""} logged</div>
                    </div>
                  );
                })}
              </div>
            </>
          )}

          {tab === "overview" && (
            <>
              <div className="section-title" style={{ marginBottom: 20 }}>GYM OVERVIEW</div>
              <div className="stats-row">
                <div className="stat-card">
                  <div className="stat-val">{workouts.length}</div>
                  <div className="stat-label">Total Workouts</div>
                </div>
                <div className="stat-card">
                  <div className="stat-val">{totalScores}</div>
                  <div className="stat-label">Scores Logged</div>
                </div>
                <div className="stat-card">
                  <div className="stat-val">{athletes.length}</div>
                  <div className="stat-label">Athletes</div>
                </div>
              </div>
              <div className="section-title" style={{ marginBottom: 16 }}>RECENT SCORES</div>
              {scores.slice(-8).reverse().map(s => {
                const w = workouts.find(w => w.id === s.workoutId);
                const a = allUsers.find(u => u.id === s.userId || u.user_id === s.userId);
                if (!w || !a) return null;
                return (
                  <div key={s.id} className="my-score-row">
                    <div style={{ width: 36, height: 36, background: "var(--orange-dim)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 13, color: "var(--orange)", fontFamily: "Barlow Condensed", flexShrink: 0, overflow: "hidden" }}>
                      {avatarSrc(a)
                        ? <img src={avatarSrc(a)} alt={formatDisplayName(a)} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                        : formatDisplayName(a).split(" ").map(n => n[0]).join("")}
                    </div>
                    <div className="my-score-wod">{formatDisplayName(a)}</div>
                    <div style={{ fontSize: 12, color: "var(--sub)", flex: 1 }}>{w.title}</div>
                    <div className="my-score-val">{s.value}</div>
                    <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
                  </div>
                );
              })}
              {onLogout && (
                <button
                  onClick={onLogout}
                  style={{
                    width: "100%", marginTop: 32, padding: "12px",
                    background: "none", border: "1px solid var(--border)",
                    borderRadius: 2, color: "var(--sub)", fontSize: 13,
                    fontFamily: "Inter, sans-serif", cursor: "pointer",
                    letterSpacing: "1px", transition: "all .15s",
                  }}
                  onMouseEnter={e => { e.target.style.borderColor = "var(--red)"; e.target.style.color = "var(--red)"; }}
                  onMouseLeave={e => { e.target.style.borderColor = "var(--border)"; e.target.style.color = "var(--sub)"; }}
                >
                  Sign Out
                </button>
              )}
            </>
          )}
        </div>
        )}
      </div>

      {/* Bottom Nav */}
      <nav className="bottom-nav">
        {navItems.map(item => {
          const unread = item.id === "chat" ? unreadMsgs : 0;
          return (
            <button
              key={item.id}
              className={`bottom-nav-item ${tab === item.id ? "active" : ""}`}
              onClick={() => setTab(item.id)}
            >
              {unread > 0 && <span className="bottom-nav-badge" />}
              <div className="bottom-nav-icon-wrap">
                <span className="bottom-nav-icon-svg"><CoachNavIcon id={item.id} /></span>
              </div>
              <span className="bottom-nav-label">{item.label}</span>
            </button>
          );
        })}
      </nav>

      {showModal && (
        <WorkoutModal
          workout={editingWod}
          onSave={handleSaveWorkout}
          onClose={() => { setShowModal(false); setEditingWod(null); }}
        />
      )}
    </>
  );
}

// ── ATHLETE VIEW ───────────────────────────────────────────────────────────
function AthleteView({ user, workouts, scores, setScores, allUsers, setAllUsers, comments, notifications, onViewProfile, messages, onPostComment, onSendMessage, onMarkConversationRead, onMarkNotificationsRead, onLogout }) {
  const [tab, setTab] = useState("today");
  const unreadMsgs = messages.filter(m => m.toId === user.id && !m.read).length;
  async function switchTab(t) {
    setTab(t);
    if (t === "notifications") {
      await onMarkNotificationsRead?.(user.id);
    }
  }
  const [selectedDate, setSelectedDate] = useState(today);
  const [scoringWod, setScoringWod] = useState(null);
  const [existingScore, setExistingScore] = useState(null);

  // Build a window of dates centered on today, ±30 days
  const [dateOffset, setDateOffset] = useState(0);
  const WINDOW = 7;
  const dates = Array.from({ length: WINDOW }, (_, i) => {
    return formatDateKey(addDays(new Date(), dateOffset + i));
  });
  const canGoFuture = dateOffset < 30;
  const canGoPast = dateOffset > -6;

  const filtered = workouts.filter(w => w.date === selectedDate);
  const myScores = scores.filter(s => s.userId === user.id);

  async function handleSaveScore(score) {
  const normalizedIncomingScore = normalizeScore(score);
  const scoreRow = {
    workout_id: normalizedIncomingScore.workoutId,
    user_id: normalizedIncomingScore.userId,
    score: normalizedIncomingScore.value,
    rx: normalizedIncomingScore.rx,
    round_values: normalizedIncomingScore.roundValues,
    notes: normalizedIncomingScore.notes || "",
  };

  const existingScoreRow =
    existingScore ||
    scores.find(
      (s) =>
        s.workout_id === normalizedIncomingScore.workoutId &&
        s.user_id === normalizedIncomingScore.userId
    );

  let data, error;

  if (existingScoreRow) {
    ({ data, error } = await supabase
      .from("scores")
      .update(scoreRow)
      .eq("id", existingScoreRow.id)
      .select());
  } else {
    ({ data, error } = await supabase
      .from("scores")
      .insert([scoreRow])
      .select());
  }

  if (error) {
    console.error("ERROR SAVING SCORE:", error);
    return;
  }

  setScores((ss) => {
    const savedScore = normalizeScore({
      ...data[0],
      rx: normalizedIncomingScore.rx,
      roundValues: normalizedIncomingScore.roundValues,
    });
    const idx = ss.findIndex((s) => s.id === savedScore.id);

    if (idx >= 0) {
      const next = [...ss];
      next[idx] = savedScore;
      return next;
    }

    return [...ss, savedScore];
  });

  setScoringWod(null);
  setExistingScore(null);
}

  const navItems = [
    { id: "today", label: "Workouts" },
    { id: "coach chat", label: "Chat" },
    { id: "my profile", label: "Profile" },
    { id: "notifications", label: "Alerts" },
  ];

  function NavIcon({ id }) {
    const s = { width: 20, height: 20, strokeWidth: 1.75, fill: "none", stroke: "currentColor", strokeLinecap: "round", strokeLinejoin: "round" };
    if (id === "today") return (
      <svg viewBox="0 0 24 24" style={s}><path d="M6.5 6.5h11v11h-11z" rx="1"/><path d="M8 2v2M16 2v2M3 8h18"/><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M8 12h.01M12 12h.01M16 12h.01M8 16h.01M12 16h.01"/></svg>
    );
    if (id === "coach chat") return (
      <svg viewBox="0 0 24 24" style={s}><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
    );
    if (id === "my profile") return (
      <svg viewBox="0 0 24 24" style={s}><circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/></svg>
    );
    if (id === "notifications") return (
      <svg viewBox="0 0 24 24" style={s}><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>
    );
    return null;
  }

  return (
    <>
      <div className="athlete-page-wrap">
      {tab === "coach chat" ? (
        <ChatView
          currentUser={user}
          allUsers={allUsers}
          messages={messages}
          onSendMessage={onSendMessage}
          onMarkConversationRead={onMarkConversationRead}
        />
      ) : (
      <div className="main">
        {tab === "today" && (
          <>
            <div className="date-nav">
              <button className="date-arrow" onClick={() => { setDateOffset(o => o - 1); }} disabled={!canGoPast}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
              </button>
              <div className="date-strip-wrap">
                <div className="date-strip">
                  {dates.map(d => (
                    <button key={d} className={`date-pill ${d === selectedDate ? "active" : ""}`} onClick={() => setSelectedDate(d)}>
                      {d === today ? "Today" : formatDate(d)}
                    </button>
                  ))}
                </div>
              </div>
              <button className="date-arrow" onClick={() => { setDateOffset(o => o + 1); }} disabled={!canGoFuture}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
              </button>
            </div>
            <div className="section-header">
              <div className="section-title">{selectedDate === today ? "TODAY'S WORKOUTS" : formatDate(selectedDate).toUpperCase()}</div>
            </div>
            {filtered.length === 0 ? (
              <GorillaEmptyState text="No workouts programmed for today" />
            ) : (
              <div className="workout-grid">
                {filtered.map(w => (
                  <WorkoutCard
                    key={w.id}
                    workout={w}
                    scores={scores.filter(s => s.workout_id === w.id)}
                    currentUser={user}
                    allUsers={allUsers}
                    onLogScore={(wod, existing) => {
  setScoringWod(wod);
  setExistingScore(existing || null);
}}
                    onEdit={() => {}}
                    onDelete={() => {}}
                    comments={comments}
                    onPostComment={onPostComment}
                    onViewProfile={onViewProfile}
                  />
                ))}
              </div>
            )}
          </>
        )}

        {tab === "notifications" && (
          <>
            <div className="section-header">
              <div className="section-title">NOTIFICATIONS</div>
            </div>
            {(() => {
              const myNotifs = notifications.filter(n => n.userId === user.id);
              return myNotifs.length === 0 ? (
                <div className="empty">
                  <div className="empty-icon">Alerts</div>
                  <div className="empty-text">No notifications yet.</div>
                </div>
              ) : (
                [...myNotifs].reverse().map(n => (
                  <div key={n.id} className="notif-item" style={{ padding: "12px 0", borderBottom: "1px solid var(--border)" }}>
                    <div className="notif-text">{n.text}</div>
                    <div className="notif-time" style={{ marginTop: 4, fontSize: 11, color: "var(--sub)" }}>{relTime(n.date)}</div>
                  </div>
                ))
              );
            })()}
          </>
        )}

        {tab === "my profile" && (
          <ProfilePage
            viewUserId={user.id}
            currentUser={user}
            allUsers={allUsers}
            setAllUsers={setAllUsers}
            scores={scores}
            workouts={workouts}
            onBack={null}
            onLogout={onLogout}
          />
        )}
      </div>
      )}
      </div>

      {/* Bottom Nav */}
      <nav className="bottom-nav">
        {navItems.map(item => {
          const unreadNotifs = item.id === "notifications" ? notifications.filter(n => n.userId === user.id && !n.read).length : 0;
          return (
            <button
              key={item.id}
              className={`bottom-nav-item ${tab === item.id ? "active" : ""}`}
              onClick={() => switchTab(item.id)}
            >
              {(item.id === "coach chat" && unreadMsgs > 0) || (item.id === "notifications" && unreadNotifs > 0) ? <span className="bottom-nav-badge" /> : null}
              <div className="bottom-nav-icon-wrap">
                <span className="bottom-nav-icon-svg"><NavIcon id={item.id} /></span>
              </div>
              <span className="bottom-nav-label">{item.label}</span>
            </button>
          );
        })}
      </nav>

      {scoringWod && (
        <ScoreModal
          workout={scoringWod}
          existingScore={existingScore}
          athleteId={user.id}
          onSave={handleSaveScore}
          onClose={() => { setScoringWod(null); setExistingScore(null); }}
        />
      )}
    </>
  );
}

// ── PROFILE PAGE ───────────────────────────────────────────────────────────
function ProfilePage({ viewUserId, currentUser, allUsers, setAllUsers, scores, workouts, onBack, onLogout }) {
  const isOwn = viewUserId === currentUser.id;
  const profileUser = normalizeUser(allUsers.find(u => u.id === viewUserId) || currentUser);
  const [editBio, setEditBio] = useState(false);
  const [bioVal, setBioVal] = useState(profileUser.bio || "");
  const fileRef = useRef();
  const userScores = scores.filter(s => s.userId === profileUser.id || s.user_id === profileUser.id);

  async function onFile(e) {
    const f = e.target.files[0]; if (!f) return;
    const r = new FileReader();
    r.onload = async (ev) => {
      const avatarData = ev.target.result;

      const { error } = await supabase
        .from("athletes")
        .update({ avatar_url: avatarData })
        .eq("id", profileUser.id);

      if (error) {
        console.error("AVATAR UPDATE ERROR:", error);
        alert("Avatar update failed. Please try again.");
        return;
      }

      setAllUsers((p) =>
        p.map((u) => (u.id === profileUser.id ? normalizeUser({ ...u, avatar_url: avatarData }) : u))
      );
    };
    r.readAsDataURL(f);
    e.target.value = "";
  }

  async function saveBio() {
    const nextBio = bioVal.trim();
    const { error } = await supabase
      .from("athletes")
      .update({ bio: nextBio })
      .eq("id", profileUser.id);

    if (error) {
      console.error("BIO UPDATE ERROR:", error);
      alert("Bio update failed. Please try again.");
      return;
    }

    setAllUsers(p => p.map(u => u.id === profileUser.id ? normalizeUser({ ...u, bio: nextBio }) : u));
    setEditBio(false);
  }

  const updated = normalizeUser(allUsers.find(u => u.id === profileUser.id) || profileUser);
  function ini(name) { return (name || "?").split(" ").map(n => n[0]).join(""); }

  return (
    <div className="main">
      {onBack && <button className="btn-sm" style={{ marginBottom: 20 }} onClick={onBack}>{"<- Back"}</button>}
      <div className="profile-hero">
        <div className="profile-av-wrap">
          <div className="profile-av">
            {updated.avatar_url ? <img src={updated.avatar_url} alt="" /> : ini(formatDisplayName(updated))}
          </div>
          {isOwn && <div className="profile-av-edit" onClick={() => fileRef.current.click()}>Edit</div>}
          <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={onFile} />
        </div>
        <div className="profile-name">{formatDisplayName(updated)}</div>
        <div className="profile-role">{updated.role}</div>
        {editBio ? (
          <div style={{ maxWidth: 340, margin: "8px auto 0" }}>
            <input className="field-input" value={bioVal} onChange={e => setBioVal(e.target.value)} style={{ marginBottom: 8 }} />
            <div style={{ display: "flex", gap: 8, justifyContent: "center" }}>
              <button className="btn-score" style={{ padding: "8px 20px", fontSize: 14 }} onClick={saveBio}>Save</button>
              <button className="btn-sm" onClick={() => setEditBio(false)}>Cancel</button>
            </div>
          </div>
        ) : (
          <>
            <div className="profile-bio">{updated.bio || (isOwn ? "No bio yet." : "")}</div>
            {isOwn && <button className="btn-sm" style={{ marginTop: 8 }} onClick={() => { setEditBio(true); setBioVal(updated.bio || ""); }}>Edit Bio</button>}
          </>
        )}
        <div className="profile-stats">
          <div style={{ textAlign: "center" }}><div className="profile-stat-val">{userScores.length}</div><div className="profile-stat-lbl">Workouts</div></div>
          <div style={{ textAlign: "center" }}><div className="profile-stat-val">{userScores.filter(s => s.rx).length}</div><div className="profile-stat-lbl">RX</div></div>
        </div>
      </div>

      <div className="section-title" style={{ marginBottom: 14 }}>SCORES</div>
      {userScores.length === 0
        ? <div className="empty"><div className="empty-icon">Scores</div><div className="empty-text">No scores logged yet.</div></div>
        : [...userScores].reverse().map(s => {
          const w = workouts.find(w => w.id === s.workoutId);
          return (
            <div key={s.id} className="my-score-row">
              <div style={{ flex: 1 }}>
                <div className="my-score-wod">{w?.title || "?"}</div>
                <div style={{ fontSize: 11, color: "var(--sub)" }}>{w?.date} - {w?.type}</div>
                {s.notes && <div style={{ fontSize: 11, color: "var(--sub)", fontStyle: "italic", marginTop: 2 }}>{s.notes}</div>}
              </div>
              <div className="my-score-val">{s.value}</div>
              <span className={`lb-rx ${s.rx ? "rx" : "sc"}`}>{s.rx ? "RX" : "SC"}</span>
            </div>
          );
        })
      }
      {isOwn && onLogout && (
        <button
          onClick={onLogout}
          style={{
            width: "100%", marginTop: 32, padding: "12px",
            background: "none", border: "1px solid var(--border)",
            borderRadius: 2, color: "var(--sub)", fontSize: 13,
            fontFamily: "Inter, sans-serif", cursor: "pointer",
            letterSpacing: "1px", transition: "all .15s",
          }}
          onMouseEnter={e => { e.target.style.borderColor = "var(--red)"; e.target.style.color = "var(--red)"; }}
          onMouseLeave={e => { e.target.style.borderColor = "var(--border)"; e.target.style.color = "var(--sub)"; }}
        >
          Sign Out
        </button>
      )}
    </div>
  );
}

// ── APP ROOT ───────────────────────────────────────────────────────────────
export default function App() {
  const [allUsers, setAllUsers] = useState([]);
  const [user, setUser] = useState(null);
  const [workouts, setWorkouts] = useState([]);
  const [scores, setScores] = useState([]);
  const [comments, setComments] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [messages, setMessages] = useState([]);
  const [appLoaded, setAppLoaded] = useState(false);
  const [sessionReady, setSessionReady] = useState(false);
  const [showNotifs, setShowNotifs] = useState(false);
  const [profileView, setProfileView] = useState(null); // userId
  const notifRef = useRef();

  useEffect(() => {
    async function loadAppData() {
      try {
        const [
          athletesResult,
          scoresResult,
          workoutsResult,
          commentsResult,
          notificationsResult,
          messagesResult,
        ] = await Promise.all([
          supabase.from("athletes").select("*"),
          supabase.from("scores").select("*"),
          supabase.from("workouts").select("*"),
          supabase.from("comments").select("*").order("created_at", { ascending: true }),
          supabase.from("notifications").select("*").order("created_at", { ascending: true }),
          supabase.from("messages").select("*").order("created_at", { ascending: true }),
        ]);

        if (!athletesResult.error && athletesResult.data) {
          setAllUsers(athletesResult.data.map(normalizeUser));
        }

        if (!scoresResult.error && scoresResult.data) {
          setScores(scoresResult.data.map(normalizeScore));
        }

        if (!workoutsResult.error && workoutsResult.data) {
          setWorkouts(workoutsResult.data.map(normalizeWorkout));
        }

        if (!commentsResult.error && commentsResult.data) {
          setComments(commentsResult.data.map(normalizeComment));
        } else if (commentsResult.error) {
          console.warn("COMMENTS LOAD ERROR:", commentsResult.error);
        }

        if (!notificationsResult.error && notificationsResult.data) {
          setNotifications(notificationsResult.data.map(normalizeNotification));
        } else if (notificationsResult.error) {
          console.warn("NOTIFICATIONS LOAD ERROR:", notificationsResult.error);
        }

        if (!messagesResult.error && messagesResult.data) {
          setMessages(messagesResult.data.map(normalizeMessage));
        } else if (messagesResult.error) {
          console.warn("MESSAGES LOAD ERROR:", messagesResult.error);
        }
      } finally {
        setAppLoaded(true);
      }
    }

    loadAppData();
  }, []);

  async function resolveSessionUser(authUser, usersList = allUsers) {
    if (!authUser?.id) return null;

    const coach = usersList.find((u) => u.role === "coach" && u.user_id === authUser.id);
    if (coach) return normalizeUser(coach);

    const existingUser = usersList.find((u) => u.user_id === authUser.id);
    if (existingUser) return normalizeUser(existingUser);

    const { data: existingAthlete, error: existingAthleteError } = await supabase
      .from("athletes")
      .select("*")
      .eq("user_id", authUser.id)
      .maybeSingle();

    if (existingAthleteError) {
      console.warn("SESSION USER LOAD ERROR:", existingAthleteError);
      return null;
    }

    let athleteRow = existingAthlete;

    if (!athleteRow) {
      const pendingName =
        authUser.user_metadata?.full_name ||
        authUser.user_metadata?.name ||
        authUser.email?.split("@")[0] ||
        "Athlete";
      const pendingGender = normalizeGenderValue(authUser.user_metadata?.gender);

      const { data: insertedAthletes, error: athleteInsertError } = await insertAthleteProfile({
        user_id: authUser.id,
        full_name: pendingName,
        role: "athlete",
        gender: pendingGender,
      });

      if (athleteInsertError) {
        console.warn("SESSION USER CREATE ERROR:", athleteInsertError);
        return null;
      }

      athleteRow = insertedAthletes?.[0];
    }

    if (!athleteRow) return null;

    const normalizedUser = normalizeUser(athleteRow);
    setAllUsers((current) => {
      if (current.some((u) => u.id === normalizedUser.id || u.user_id === normalizedUser.user_id)) {
        return current;
      }
      return [...current, normalizedUser];
    });
    return normalizedUser;
  }

  useEffect(() => {
    if (!appLoaded) return undefined;

    let active = true;

    async function restoreSession() {
      try {
        const { data } = await supabase.auth.getSession();
        const sessionUser = data.session?.user;

        if (!active) return;

        if (!sessionUser) {
          setUser(null);
          setSessionReady(true);
          return;
        }

        const resolvedUser = await resolveSessionUser(sessionUser, allUsers);
        if (!active) return;

        setUser(resolvedUser);
      } finally {
        if (active) setSessionReady(true);
      }
    }

    restoreSession();

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (!active) return;

      if (event === "SIGNED_OUT" || !session?.user) {
        setUser(null);
        setProfileView(null);
        setSessionReady(true);
        return;
      }

      const resolvedUser = await resolveSessionUser(session.user, allUsers);
      if (!active) return;

      setUser(resolvedUser);
      setSessionReady(true);
    });

    return () => {
      active = false;
      subscription.unsubscribe();
    };
  }, [appLoaded, allUsers]);

  useEffect(() => {
    const h = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) {
        setShowNotifs(false);
      }
    };

    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  function openNotifs() {
    setShowNotifs((v) => !v);
    setNotifications((p) =>
      p.map((n) => (n.userId === user?.id ? { ...n, read: true } : n))
    );
  }

  function handleLogin(u) {
    // sync in case avatar/bio updated
    const fresh = normalizeUser(allUsers.find((x) => x.id === u.id) || u);
    setUser(fresh);
  }

  async function handleLogout() {
    setProfileView(null);
    await supabase.auth.signOut();
    setUser(null);
  }

  async function createNotification({ userId, text }) {
    const notificationRow = {
      user_id: userId,
      text,
      read: false,
    };

    const { data, error } = await supabase
      .from("notifications")
      .insert([notificationRow])
      .select()
      .single();

    if (error) {
      console.error("ERROR CREATING NOTIFICATION:", error);
      return false;
    }

    const savedNotification = normalizeNotification(data);
    setNotifications((p) => [...p, savedNotification]);
    return savedNotification;
  }

  async function handlePostComment({ scoreId, ownerId, authorId, text }) {
    const commentRow = {
      score_id: scoreId,
      author_id: authorId,
      text,
    };

    const { data, error } = await supabase
      .from("comments")
      .insert([commentRow])
      .select()
      .single();

    if (error) {
      console.error("ERROR SAVING COMMENT:", error);
      return false;
    }

    setComments((p) => [...p, normalizeComment(data)]);

    if (ownerId && ownerId !== authorId) {
      const author = allUsers.find((u) => u.id === authorId || u.user_id === authorId);
      await createNotification({
        userId: ownerId,
        text: `${formatDisplayName(author)} commented on your score`,
      });
    }

    return true;
  }

  async function handleSendMessage({ fromId, toId, text }) {
    const messageRow = {
      from_id: fromId,
      to_id: toId,
      text,
      read: false,
    };

    const { data, error } = await supabase
      .from("messages")
      .insert([messageRow])
      .select()
      .single();

    if (error) {
      console.error("ERROR SAVING MESSAGE:", error);
      return false;
    }

    setMessages((p) => [...p, normalizeMessage(data)]);

    const sender = allUsers.find((u) => u.id === fromId || u.user_id === fromId);
    const preview = text.length > 40 ? `${text.slice(0, 40)}...` : text;

    await createNotification({
      userId: toId,
      text: `${formatDisplayName(sender)}: ${preview}`,
    });

    return true;
  }

  async function handleMarkConversationRead(currentUserId, otherUserId) {
    setMessages((ms) =>
      ms.map((m) =>
        m.fromId === otherUserId && m.toId === currentUserId ? { ...m, read: true } : m
      )
    );

    const { error } = await supabase
      .from("messages")
      .update({ read: true })
      .eq("to_id", currentUserId)
      .eq("from_id", otherUserId)
      .eq("read", false);

    if (error) {
      console.error("ERROR MARKING MESSAGES READ:", error);
    }
  }

  async function handleMarkNotificationsRead(userId) {
    setNotifications((p) => p.map((n) => (n.userId === userId ? { ...n, read: true } : n)));

    const { error } = await supabase
      .from("notifications")
      .update({ read: true })
      .eq("user_id", userId)
      .eq("read", false);

    if (error) {
      console.error("ERROR MARKING NOTIFICATIONS READ:", error);
    }
  }

  if (!appLoaded || !sessionReady) {
    return (
      <div className="app">
        <StyleTag />
        <div className="login-wrap">
          <div className="login-bg" />
          <div className="login-card" style={{ zIndex: 1, textAlign: "center" }}>
            <div className="section-title" style={{ marginBottom: 8 }}>LOADING</div>
            <div style={{ color: "var(--sub)", fontSize: 13 }}>Loading your gym data...</div>
          </div>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="app">
        <StyleTag />
        <LoginScreen
          onLogin={handleLogin}
          users={allUsers}
          setUsers={setAllUsers}
        />
      </div>
    );
  }

  if (profileView) {
    return (
      <div className="app">
        <StyleTag />
        <div ref={notifRef} style={{ position: "relative" }}>
          <Nav user={user} />
        </div>
        <ProfilePage
          viewUserId={profileView}
          currentUser={user}
          allUsers={allUsers}
          setAllUsers={setAllUsers}
          scores={scores}
          workouts={workouts}
          onBack={() => setProfileView(null)}
        />
      </div>
    );
  }

  const sharedProps = {
    allUsers,
    setAllUsers,
    comments,
    notifications,
    onViewProfile: setProfileView,
    messages,
    onPostComment: handlePostComment,
    onSendMessage: handleSendMessage,
    onMarkConversationRead: handleMarkConversationRead,
    onMarkNotificationsRead: handleMarkNotificationsRead,
  };

  return (
    <div className="app">
      <StyleTag />
      <Nav user={user} onLogout={null} />
      {user.role === "coach" ? (
        <CoachView
          user={user}
          workouts={workouts}
          scores={scores}
          setWorkouts={setWorkouts}
          setScores={setScores}
          onLogout={handleLogout}
          {...sharedProps}
        />
      ) : (
        <AthleteView
          user={user}
          workouts={workouts}
          scores={scores}
          setScores={setScores}
          onLogout={handleLogout}
          {...sharedProps}
        />
      )}
    </div>
  );
}
